VALUES
  ('disabled-10ced7e2-moex-00160', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於政府資訊公開法之敘述，下列何者錯誤？', '["係以保障人民知的權利，增進人民對公共事務之瞭解、信賴及監督為 目的", "依該法規定，公開之對象為一般人民", "申請人依該法規定申請行政機關提供行政資訊遭拒絕者，如有不服，僅 得於對實體決定聲明不服時，一併聲明之", "依該法規定申請行政機關提供行政資訊之權利，屬實體權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00161', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '土地所有權人甲於1月3日收到新北市政府工務局所開立「申請建築執照 補件通知單」，通知其應於30日內依建築法規定補件，但甲不服並於3月 3日提起訴願。下列何者正確？', '["該補件通知單之性質為觀念通知", "甲提起之訴願已逾訴願期間，訴願管轄機關應以無理由駁回甲之訴願", "甲不服該補件通知單，應向內政部提起訴願", "該補件通知單具有強制效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00162', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '甲在河流旁搭建工寮並開闢菜園，經主管機關認定妨害水土保持屬於違 法，命甲限期回復原狀。甲不服，除循序提起訴願救濟外，得以下列何種 程序在救濟進行期間實現暫時權利保護？', '["應向行政法院聲請定暫時狀態假處分，由法院裁定該工寮及菜園暫時為 合法", "應向行政法院聲請保全處分，保全工寮及菜園之事實狀態", "應依據行政執行法向主管機關聲明異議", "應依行政訴訟法或訴願法聲請暫時停止執行該命回復原狀之處分 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00163', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '下列何者非屬確認行政處分無效之訴的實體判決要件？', '["確認對象須為行政處分之無效", "須已向原處分機關請求確認其無效未被允許或不為確答", "須經訴願程序而遭駁回", "須有即受確認判決之法律上利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00164', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["收容聲請事件適用以原就被之原則", "對於已執行而無回復原狀可能之行政處分，得提起確認該行政處分無效 之訴訟", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允 許，或經請求後於30日內不為確答者，始得提起之", "受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00165', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於國家賠償法所規定之公共設施國家賠償責任，下列何者正確？', '["當公共設施已委託民間團體或個人管理時，國家即免除損害賠償責任", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體 或個人已就使用該公物為適當之警告或標示，而人民仍從事冒險或具危 險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物內之設施，經管理機關、受委託管理之 民間團體或個人已就使用該公物為適當之警告或標示，而人民仍從事冒 險或具危險性活動，國家不負損害賠償責任", "就公共設施設置或管理之瑕疵應負責之第三人，賠償機關對之並無求 償權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00166', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-113-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["錯誤施打疫苗造成人民身體健康受損，基於準徵收法理應予補償", "對於犯罪被害人所為之補償，非基於特別犧牲", "土地徵收為合法、有目的性對人民財產權之侵害，故須給予補償", "為防止公益重大危害而廢止授益處分時，受益人得請求信賴利益損失 補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00167', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '甲將其所有之 A地出售給乙，並委請地政士丙代為辦理所有權移轉登記。
惟因丙業務繁忙的疏失，致將甲所有之 B 地亦一併連同 A 地移轉登記於
乙，嗣後甲發現丙登記錯誤，遂請求塗銷乙對 B地之所有權登記並返還 B
地，是否應予准許？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "4359c243abf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00168', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '甲有線電視公司於民國 100年間向台電公司租用電桿及電纜線（合稱為一
附架點）供傳輸訊號所用，雙方於租約中載明共租用附架點 350點。然 106
年間台電公司進行普查時，卻發現甲公司實際使用的附架點高達6,700點。
台電公司至 110年 5 月間起訴，請求甲公司依其實際使用附架點的數量給
付租金或返還相當於租金之利益。甲公司則以，台電公司出租電桿及電纜
線為營業出租動產，適用 2 年短期消滅時效，其自得拒絕給付，資為抗辯。
試問，甲公司的主張是否有理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "4359c243abf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00169', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-b96fcbef', 'sub-disabled-10ced7e2-04', NULL, 'essay', '甲為警員，一日與其上級直屬長官乙警官共同執行巡邏勤務。乙見一路人
A神色緊張，查覺有異，上前欲臨檢 A。A見狀便向甲、乙二人質疑臨檢
合法性，隨後便欲離去。乙見 A不配合臨檢，甚至還出口質疑，即命令甲
動用強制力攔阻A，擬將 A帶回警局查辦。甲聽完乙之命令後，心中認為
此一臨檢確實不符合警察職權行使法之規定，乙要求動用強制力之命令亦
不合法，但心想乙是長官，應顧及乙之面子，不願違抗乙之命令，遂依命
令以柔道大外割之動作將 A 摔倒在地，致 A 肩膀輕微脫臼、皮膚受有擦
挫傷。試問，甲之行為是否應負刑事責任？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "4359c243abf0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL)
